import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useNavigate } from 'react-router-dom';
import Login from './authentication/Login';
import Register from './authentication/register';
import Dashboard from './components/Dashboard';
import UserProfile from './components/UserProfile';
import ProductList from './components/ProductList';
import ShoppingCart from './components/ShoppingCart';
import SearchBar from './components/SearchBar';
import AdminPanel from './components/AdminPanel';
import ErrorBoundary from './components/ErrorBoundary';
import { AppProvider, useAppContext } from './context/AppContext';
// ✅ FIXED: Imported the missing API hooks needed for cart synchronization loops
import { fetchUserCartFromServer, syncUserCartToServer } from './utils/api';
import './styles/App.css';

function App() {
  const [user, setUser] = useState(null);
  const [cart, setCart] = useState([]);
  const [theme, setTheme] = useState("light");

  useEffect(() => {
    const savedUser = localStorage.getItem("currentUser");
    if (savedUser) {
      try {
        setUser(JSON.parse(savedUser));
      } catch (e) {
        console.error(e);
      }
    }
  }, []);

  useEffect(() => {
    console.log("Page viewed:", window.location.pathname);
  }, []);

  function handleLogin(userData) {
    setUser(userData);
    localStorage.setItem("currentUser", JSON.stringify(userData));
  }

  function handleLogout() {
    setUser(null);
    localStorage.removeItem("currentUser");
  }

  // Triggered automatically whenever user login credentials state modifications occur
  useEffect(() => {
    if (user) {
      fetchUserCartFromServer(user.name).then(cloudCart => {
        if (cloudCart && cloudCart.items) {
          setCart(cloudCart.items);
        }
      });
    } else {
      setCart([]);
    }
  }, [user]);

  // Sync state modifications dynamically up to cloud schemas
  function addToCart(item) {
    setCart(prevCart => {
      const updatedCart = [...prevCart, { ...item, quantity: 1 }];
      if (user) {
        syncUserCartToServer(user.name, updatedCart);
      }
      return updatedCart;
    });
  }

  function switchTheme(newTheme) {
    setTheme(newTheme);
  }

  return (
    <AppProvider>
      <ErrorBoundary>
        <div className={`app ${theme}`}>
          <nav className="navbar">
            <Link to="/">Home</Link>
            <Link to="/products">Products</Link>
            <Link to="/cart">Cart ({cart.length})</Link>
            <Link to="/search">Search</Link>
            {user ? (
              <>
                <Link to="/dashboard">Dashboard</Link>
                <Link to={`/profile/${user.id || "me"}`}>Profile</Link>
                <button onClick={handleLogout}>Logout</button>
                {user.role === "admin" && <Link to="/admin">Admin</Link>}
              </>
            ) : (
              <Link to="/login">Login</Link>
            )}
          </nav>

          <main>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={<Login onLogin={handleLogin} />} />
              
              <Route path="/dashboard" element={<Dashboard user={user} />} />
              <Route path="/profile/:id" element={<UserProfile />} />
              <Route path="/products" element={<ProductList addToCart={addToCart} />} />
              <Route path="/cart" element={<ShoppingCart cart={cart} setCart={setCart} />} />
              <Route path="/search" element={<SearchBar />} />
              <Route path="/admin" element={<AdminPanel user={user} />} />
            </Routes>
          </main>
        </div>
      </ErrorBoundary>
    </AppProvider>
  );
}

// ✅ FIXED: Kept exactly ONE clean, safe, un-nested Home component declaration
function Home() {
  const [count, setCount] = useState(0);
  const { state = { user: null } } = useAppContext();

  useEffect(() => {
    const timer = setInterval(() => {
      setCount(c => c + 1);
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="home">
      <h1>Welcome {state?.user?.name ? ", " + state.user.name : ""}!</h1>
      {count > 0 && <p>You have been here for {count} seconds</p>}
    </div>
  );
}

export default App;
